Great! Look at lines 3348-3359. There's already a pattern for exactly our case! Indeed, they have:

```
// (zext i1 A) + (zext i1 B) == 1 --> xor A, B
// (zext i1 A) + (zext i1 B) != 1 --> not (xor A, B)
Value *A, *B;
if (C.isOne() &&
    match(BOp0, m_ZExt(m_Value(A))) && A->getType()->getScalarSizeInBits() == 1 &&
    match(BOp1, m_ZExt(m_Value(B))) && B->getType()->getScalarSizeInBits() == 1) {
  Value *Xor = Builder.CreateXor(A, B);
  if (Pred == ICmpInst::ICMP_EQ)
    return replaceInstUsesWith(Cmp, Xor);
  // ICMP_NE
  return BinaryOperator::CreateNot(Xor);
